from dataclasses import dataclass, field
from typing import Literal

CoverageStatus = Literal["COVERED", "EXCLUDED", "SILENT", "NOT_ASSESSED"]
PolicyLine = Literal[
    "IP_MEDIA_LIABILITY", "CGL", "CYBER_TECH_EO",
    "EPL", "PROFESSIONAL_INDEMNITY", "BUSINESS_INTERRUPTION"
]

@dataclass
class PolicyAIReview:
    policy_line: PolicyLine
    insurer: str
    policy_number: str
    renewal_date: str
    limit_usd: float
    ai_exclusion_found: bool
    ai_exclusion_text: str
    ai_endorsement_available: bool
    endorsement_premium_usd: float | None
    coverage_status: CoverageStatus
    assessed_by: str
    assessment_date: str
    notes: str = ""

    def annual_premium_impact(self) -> str:
        if self.endorsement_premium_usd is None:
            return "Not quoted"
        return f"${self.endorsement_premium_usd:,.0f}/year to add AI coverage"

    def summary(self) -> str:
        excl = " [AI EXCLUDED]" if self.ai_exclusion_found else ""
        return (
            f"{self.policy_line} ({self.insurer}){excl}: "
            f"Status={self.coverage_status} | "
            f"Limit=${self.limit_usd:,.0f} | "
            f"AI endorsement={'available' if self.ai_endorsement_available else 'not available'}"
        )


@dataclass
class AIInsuranceProgramme:
    enterprise_name: str
    review_date: str
    policies: list[PolicyAIReview]

    def uncovered_risks(self) -> list[str]:
        covered_lines = {p.policy_line for p in self.policies if p.coverage_status == "COVERED"}
        all_lines = {
            "IP_MEDIA_LIABILITY", "CGL", "CYBER_TECH_EO",
            "EPL", "PROFESSIONAL_INDEMNITY", "BUSINESS_INTERRUPTION"
        }
        return list(all_lines - covered_lines)

    def total_ai_limit(self) -> float:
        return sum(p.limit_usd for p in self.policies if p.coverage_status == "COVERED")

    def excluded_policies(self) -> list[PolicyAIReview]:
        return [p for p in self.policies if p.ai_exclusion_found]

    def programme_summary(self) -> str:
        covered = sum(1 for p in self.policies if p.coverage_status == "COVERED")
        excluded = len(self.excluded_policies())
        uncovered = len(self.uncovered_risks())
        return (
            f"{self.enterprise_name} AI Insurance Review ({self.review_date}): "
            f"{covered} lines covered | {excluded} exclusions found | "
            f"{uncovered} risk categories uncovered | "
            f"Total AI coverage limit: ${self.total_ai_limit():,.0f}"
        )

from dataclasses import dataclass

@dataclass
class AIExposureModel:
    feature_name: str
    annual_output_volume: int
    estimated_error_rate: float        # 0.0–1.0 (fraction of outputs that are errors)
    harm_conversion_rate: float        # fraction of errors that cause actual harm
    average_harm_cost_usd: float       # average cost per harmful output incident
    catastrophic_scenario_usd: float   # worst-case single incident (class action, regulatory fine)
    catastrophic_probability: float    # annual probability of catastrophic scenario (0.0–1.0)

    def expected_annual_exposure(self) -> float:
        """Expected value of liability from normal error distribution."""
        return (
            self.annual_output_volume *
            self.estimated_error_rate *
            self.harm_conversion_rate *
            self.average_harm_cost_usd
        )

    def tail_risk_exposure(self) -> float:
        """Expected value contribution from catastrophic scenario."""
        return self.catastrophic_scenario_usd * self.catastrophic_probability

    def total_expected_annual_exposure(self) -> float:
        return self.expected_annual_exposure() + self.tail_risk_exposure()

    def recommended_minimum_limit(self) -> float:
        """Conservative rule: insure for 5x expected or catastrophic, whichever is larger."""
        return max(
            self.expected_annual_exposure() * 5,
            self.catastrophic_scenario_usd
        )

    def exposure_summary(self) -> str:
        return (
            f"{self.feature_name}: "
            f"Expected annual exposure ${self.expected_annual_exposure():,.0f} | "
            f"Tail risk ${self.tail_risk_exposure():,.0f} | "
            f"Total ${self.total_expected_annual_exposure():,.0f} | "
            f"Recommended minimum limit ${self.recommended_minimum_limit():,.0f}"
        )
